resolve: {
  alias: {
    "@": fileURLToPath(new URL("./src", import.meta.url)),
  },
  // Deduplicate packages that ship in multiple workspace node_modules
  // (e.g. `packages/ui` pins lucide-react 0.486 while `apps/org-next` is
  // on 0.577). Without dedupe, the SSR module graph and the client graph
  // can resolve different copies, producing hydration mismatches like
  // lucide's default `aria-hidden="true"` on server vs unset on client,
  // which breaks event-handler attachment on the affected subtree.
  dedupe: ["lucide-react", "react", "react-dom"],
},

